import BlurFade from '@/components/magicui/blur-fade';
import ThoughtsList from '@/components/thoughts-list';
import { promises as fs } from 'fs';
import type { Metadata } from 'next';
import path from 'path';

export const metadata: Metadata = {
  title: 'Thoughts',
  description: '我的碎碎念'
};

async function getThoughts() {
  try {
    const filePath = path.join(process.cwd(), 'content', 'thoughts.json');
    const data = await fs.readFile(filePath, 'utf8');
    return JSON.parse(data);
  } catch {
    return { thoughts: [], lastSync: null, totalCount: 0 };
  }
}

export default async function ThoughtsPage() {
  const { thoughts } = await getThoughts();

  return (
    <main className='mx-auto flex min-h-[100dvh] w-full max-w-4xl flex-col space-y-10 px-4 pb-24 pt-6 sm:px-6 sm:pb-28 sm:pt-10 lg:px-8'>
      <section id='thoughts'>
        <div className='mx-auto w-full max-w-2xl space-y-8'>
          <BlurFade delay={0.04}>
            <h1 className='text-3xl font-bold'>Thoughts</h1>
            <p className='text-muted-foreground'>来自 kk 的碎碎念</p>
          </BlurFade>

          {thoughts.length === 0 ? (
            <p className='text-muted-foreground text-center py-12'>暂无内容</p>
          ) : (
            <ThoughtsList thoughts={thoughts} />
          )}
        </div>
      </section>
    </main>
  );
}

'use client';

import BlurFade from '@/components/magicui/blur-fade';
import {
  assets,
  categoryLabels,
  philosophy,
  type AssetCategory
} from '@/data/fund';
import { BookOpenIcon, ExternalLinkIcon } from 'lucide-react';
import Link from 'next/link';
import { useState } from 'react';

const BLUR_FADE_DELAY = 0.04;

const categories: Array<{ key: AssetCategory | 'all'; label: string }> = [
  { key: 'all', label: 'All' },
  ...Object.entries(categoryLabels).map(([key, label]) => ({
    key: key as AssetCategory,
    label
  }))
];

export default function FundClient() {
  const [selectedCategory, setSelectedCategory] = useState<
    AssetCategory | 'all'
  >('all');

  const filteredAssets = assets.filter((asset) =>
    selectedCategory === 'all' ? true : asset.category === selectedCategory
  );

  return (
    <section className='overflow-x-clip'>
      <BlurFade delay={BLUR_FADE_DELAY}>
        <h1 className='font-medium text-2xl mb-4 tracking-tighter'>fund</h1>
      </BlurFade>

      <BlurFade delay={BLUR_FADE_DELAY * 1.5}>
        <div className='space-y-2 mb-2 text-sm text-muted-foreground'>
          <p>{philosophy.intro}</p>
          <p>{philosophy.principle}</p>
          <p>{philosophy.criteria}</p>
          <p className='italic'>{philosophy.thought}</p>
        </div>
        <p className='text-xs text-muted-foreground mb-8'>
          DYOR! DYOR! DYOR! Last updated:{' '}
          <span className='font-medium'>{philosophy.lastUpdated}</span>
        </p>
      </BlurFade>

      <BlurFade delay={BLUR_FADE_DELAY * 2}>
        <div className='flex flex-wrap gap-2 mb-8'>
          {categories.map((cat) => (
            <button
              key={cat.key}
              onClick={() => setSelectedCategory(cat.key)}
              className={`px-3 py-1 rounded text-xs font-medium transition-colors ${
                selectedCategory === cat.key
                  ? 'bg-primary text-primary-foreground'
                  : 'bg-secondary text-secondary-foreground hover:bg-secondary/80'
              }`}>
              {cat.label}
            </button>
          ))}
        </div>
      </BlurFade>

      <div className='grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4'>
          {filteredAssets.map((asset, id) => (
            <BlurFade
              delay={BLUR_FADE_DELAY * 3 + id * 0.05}
              key={`${asset.name}-${asset.category}`}>
              <div className='border rounded-lg p-4 h-full flex flex-col'>
                <div className='flex items-start justify-between mb-2'>
                  <div>
                    <h3 className='font-semibold'>{asset.name}</h3>
                    {asset.ticker && (
                      <span className='text-xs text-muted-foreground'>
                        {asset.ticker}
                      </span>
                    )}
                  </div>
                  <div className='flex flex-col items-end gap-1 shrink-0'>
                    <span className='text-xs px-2 py-0.5 rounded bg-secondary text-secondary-foreground'>
                      {categoryLabels[asset.category]}
                    </span>
                    {asset.isPrivate && (
                      <span className='text-xs px-2 py-0.5 rounded bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-400'>
                        private
                      </span>
                    )}
                    {asset.category === 'prediction' && (
                      asset.hasToken && asset.tokenTicker ? (
                        <a
                          href={asset.coingeckoLink}
                          target='_blank'
                          rel='noopener noreferrer'
                          className='text-xs px-2 py-0.5 rounded bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 hover:opacity-80 transition-opacity'>
                          ${asset.tokenTicker}
                        </a>
                      ) : asset.coingeckoLink ? (
                        <a
                          href={asset.coingeckoLink}
                          target='_blank'
                          rel='noopener noreferrer'
                          className='text-xs px-2 py-0.5 rounded bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-400 hover:opacity-80 transition-opacity'>
                          no token ↗
                        </a>
                      ) : (
                        <span className='text-xs px-2 py-0.5 rounded bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-400'>
                          no token
                        </span>
                      )
                    )}
                  </div>
                </div>
                <p className='text-sm text-muted-foreground flex-1'>
                  {asset.description}
                </p>
                {(asset.link || asset.researchLink) && (
                  <div className='flex items-center gap-3 mt-3 pt-3 border-t'>
                    {asset.link && (
                      <a
                        href={asset.link}
                        target='_blank'
                        rel='noopener noreferrer'
                        className='flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors'>
                        <ExternalLinkIcon className='size-3' />
                        Site
                      </a>
                    )}
                    {asset.researchLink && (
                      <Link
                        href={asset.researchLink}
                        className='flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors'>
                        <BookOpenIcon className='size-3' />
                        Research
                      </Link>
                    )}
                  </div>
                )}
              </div>
            </BlurFade>
          ))}
      </div>
    </section>
  );
}

